function.body:
TYPE RECORD IS REF CURSOR;
  Cur_Parameter RECORD;
  Cur_PaymentMethod RECORD;


  v_User_ID VARCHAR2(32) ;
  v_ClosingDate DATE;
  v_ResultStr VARCHAR2(2000) := '';
  v_Concept_ID VARCHAR2(32);
  v_LoadLines VARCHAR2(60);
  v_RecordId VARCHAR2(32);
  v_OrganizationId VARCHAR2(32);
  v_Contador NUMBER:=0; 
  v_TotalIncome NUMBER:=0; 
  v_TotalExpenses NUMBER:=0; 
  v_Docstatus VARCHAR2(60); 
  v_PeriodStatus  VARCHAR(60);--OBTG:VARCHAR2--
  v_ContadorLineas NUMBER:=0;
  v_TotalIncome2 NUMBER:=0; 
  v_TotalExpenses2 NUMBER:=0; 
  v_module NUMBER:=0; 
  v_Grandtotal NUMBER:=0; 
  v_type_payment  VARCHAR2(60);
  v_id  VARCHAR2(32);
  v_doctypesales VARCHAR2(32);
  v_doctypecreditnote VARCHAR2(32);
  v_total NUMBER:=0; 
  v_totalsales NUMBER:=0; 
  v_creditnotes NUMBER:=0;   
  v_setup_id VARCHAR2(32);
  v_preference VARCHAR2(60);

BEGIN

  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || PInstance_ID) ;
  v_ResultStr := 'PInstanceNotFound';
  AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'Y', NULL, NULL) ;

  BEGIN --BODY

-- GET:    
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date,
        p.AD_Client_ID,
        p.AD_Org_ID,
        p.CreatedBy        
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
           ON i.AD_PInstance_ID = p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID = pinstance_id
      ORDER BY p.SeqNo
      )
    LOOP
        v_RecordId := Cur_Parameter.Record_ID;

      IF (Cur_Parameter.ParameterName = 'Ad_User_ID') THEN
        v_User_ID := Cur_Parameter.P_String;      
      END IF;    

    END LOOP;  

        SELECT record,ad_org_id,closingdate,docstatus,sccc_setup_id INTO v_LoadLines,v_OrganizationId,v_ClosingDate,v_Docstatus,v_setup_id FROM sccc_cash_clousure where sccc_cash_clousure_id= v_RecordId;

	 --COMPROBAR EXISTENCIA MÓDULO ec.com.sidesoft.custom.closecash.advanced
	SELECT 
	COALESCE((SELECT COUNT(*) AS CONTAR FROM AD_MODULE WHERE JAVAPACKAGE = 'ec.com.sidesoft.custom.closecash.advanced'),0)
	INTO v_Module
	FROM DUAL;

	--SE COMPRUEBA SI EL PERÍODO ESTÁ CERRADO
	SELECT openclose INTO v_PeriodStatus FROM c_period WHERE v_ClosingDate>=startdate AND v_ClosingDate <= enddate;
	IF ( v_PeriodStatus='O')THEN
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@PeriodNotAvailable@') ;
		RETURN;
	END IF;

    IF(v_LoadLines ='SCCC_RE') THEN

	SELECT count(*) INTO v_ContadorLineas FROM sccc_cash_clousureline WHERE sccc_cash_clousure_ID= v_RecordId ;
	IF (v_ContadorLineas=0) THEN  
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@SCCC_LINES_NOT_FOUND@') ;
		RETURN;
	END IF;



	SELECT coalesce(sum(amount),0) INTO v_TotalIncome FROM sccc_cash_clousureline 
	WHERE sccc_cash_clousure_ID= v_RecordId AND Typeaccount='INC';

	SELECT coalesce(sum(abs(amount)),0) INTO v_TotalExpenses FROM sccc_cash_clousureline
	WHERE sccc_cash_clousure_ID= v_RecordId AND Typeaccount='EXP';

	IF (v_Module>0) THEN
		EXECUTE IMMEDIATE 'SELECT coalesce(sum(amount),0) FROM scca_cash_clousureline2 
		WHERE sccc_cash_clousure_ID='''|| v_RecordId ||''' AND Typeaccount=''INC'' ' INTO v_TotalIncome2; 

		EXECUTE IMMEDIATE 'SELECT coalesce(sum(abs(amount)),0) FROM scca_cash_clousureline2
		WHERE sccc_cash_clousure_ID='''|| v_RecordId ||''' AND Typeaccount=''EXP'' ' INTO v_TotalExpenses2; 
	END IF;

	v_Grandtotal:= COALESCE(v_TotalIncome,0)+COALESCE(v_TotalIncome2,0)-COALESCE(v_TotalExpenses,0)-COALESCE(v_TotalExpenses2,0);


        IF (v_Grandtotal=0) THEN

		DBMS_OUTPUT.PUT_LINE('@SCCC_TOTAL_ZERO@') ;
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@SCCC_TOTAL_ZERO@') ;
		RETURN;

	END IF;

    SELECT COALESCE(( 	SELECT value
                        FROM ad_preference
                        WHERE property = 'Sccc_CloseCashDoctype'
                        AND created = ( SELECT MAX(created) FROM ad_preference 
                        WHERE property = 'Sccc_CloseCashDoctype')
                ),'N')
    INTO v_preference
    FROM DUAL;      

	IF (v_preference='N') THEN
		SELECT 
		SUM(
		CASE WHEN dt.isreversal='Y' OR dt.isreturn='Y' THEN
			abs(ci.totalpaid)*-1
		ELSE
			ci.totalpaid
		END
		) INTO v_total
		FROM c_invoice ci
		LEFT JOIN c_doctype dt ON ci.c_doctype_id = dt.c_doctype_id
		WHERE ci.docstatus='CO' AND ci.issotrx='Y' 
		AND ci.ad_org_id=v_OrganizationId AND TO_DATE(ci.dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy');
	ELSE

		IF(v_setup_id IS NULL) THEN
		 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@Sccc_SetupNotSet@') ;
			RETURN;			
		END IF;

		SELECT c_doctype_sales_id, c_doctype_credit_notes_id
		INTO v_doctypesales, v_doctypecreditnote
		FROM sccc_setup 
		WHERE sccc_setup_id = v_setup_id;

		IF (v_doctypesales IS NULL OR v_doctypecreditnote IS NULL) THEN
		 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@Sccc_DocTypeNull@') ;
			RETURN;
		END IF;		

		SELECT sum(totalpaid) INTO v_totalsales
		FROM c_invoice
		WHERE 
		TO_DATE(dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy') AND c_doctype_id = v_doctypesales
		AND docstatus='CO' AND issotrx='Y' ;

		SELECT sum(totalpaid) INTO v_creditnotes
		FROM c_invoice
		WHERE
		TO_DATE(dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy') AND c_doctype_id = v_doctypecreditnote
		AND docstatus='CO' AND issotrx='Y' ;	

		v_total := ABS(COALESCE(v_totalsales,0))-ABS(COALESCE(v_creditnotes,0));

	END IF;

	UPDATE sccc_cash_clousure SET docstatus='SCCC_RG' WHERE sccc_cash_clousure_ID= v_RecordId;
	UPDATE sccc_cash_clousure SET totalincome= v_TotalIncome + v_TotalIncome2, totalexpenses= v_TotalExpenses + v_TotalExpenses2 
	,totalsales = COALESCE(v_total,0), difference=COALESCE(v_total,0)-COALESCE(v_Grandtotal,0)
	 WHERE sccc_cash_clousure_ID= v_RecordId ;
	UPDATE sccc_cash_clousure SET record='RE' WHERE sccc_cash_clousure_ID= v_RecordId;

    ELSE
	    IF(v_LoadLines ='RE' AND v_Docstatus='SCCC_RG') THEN
		UPDATE sccc_cash_clousure SET docstatus='DR',totalincome=0,totalexpenses=0,totalsales=0,difference=0 WHERE sccc_cash_clousure_ID= v_RecordId;
		UPDATE sccc_cash_clousure SET record='SCCC_RE' WHERE sccc_cash_clousure_ID= v_RecordId;
	    END IF;
    END IF; 

    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 1, '@Success@') ;
    RETURN;

  END; --BODY
  EXCEPTION
  WHEN OTHERS THEN
    v_ResultStr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
    RETURN;
END SCCC_RECORD
